            transform: scaleX(0);
            transition: transform 0.3s ease;
        }

        .location-card::after {
            content: '';
            position: absolute;
            top: 50%;
            left: 50%;
            width: 0;
            height: 0;
            background: var(--accent-primary);
            border-radius: 50%;
            transform: translate(-50%, -50%);
            transition: all 0.3s ease;
            pointer-events: none;
            opacity: 0.05;
        }

        .location-card:active::after {
            width: 400px;
            height: 400px;
        }

        .location-card:hover::before {
            transform: scaleX(1);
        }

        .location-card:hover {
            transform: translateY(-5px) translateZ(0);
            border-color: var(--accent-primary);
            box-shadow: 0 15px 40px rgba(0, 0, 0, 0.3);
        }

        .location-name {
            font-size: 18px;
            font-weight: 600;
            color: var(--text-primary);
            margin-bottom: 10px;
            transition: color var(--theme-transition-speed) ease;
        }

        .location-desc {
            font-size: 14px;
            color: var(--text-secondary);
            line-height: 1.6;
            transition: color var(--theme-transition-speed) ease;
        }

        .announcement-modal {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(0, 0, 0, 0.5);
            z-index: 10000;
            display: none;
            backdrop-filter: blur(3px);
            animation: fadeIn 0.3s ease;
        }

        .announcement-modal.show {
            display: block;
        }

        @keyframes fadeIn {
            from {
                opacity: 0;
            }
            to {
                opacity: 1;
            }
        }

        .announcement-modal-content {
            background: var(--bg-card);
            border: 2px solid var(--border-color);
            border-radius: 20px;
            padding: 30px;
            max-width: 600px;
            width: 90%;
            max-height: 400px;
            overflow-y: auto;
            position: absolute;
            top: 100px; 
            left: 50%;
            transform: translateX(-50%);
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
            animation: slideInDown 0.3s ease;
        }

        @keyframes slideInDown {
            from {
                opacity: 0;
                transform: translateX(-50%) translateY(-30px);
            }
            to {
                opacity: 1;
                transform: translateX(-50%) translateY(0);
            }
        }

        .announcement-modal-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 20px;
            padding-bottom: 15px;
            border-bottom: 2px solid var(--border-color);
        }

        .announcement-modal-title {
            font-size: 20px;
            font-weight: 700;
            color: var(--text-primary);
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .announcement-modal-close {
            background: none;
            border: none;
            font-size: 24px;
            color: var(--text-muted);
            cursor: pointer;
            transition: all 0.3s ease;
            border-radius: 50%;
            width: 40px;
            height: 40px;
            display: flex;
            align-items: center;
            justify-content: center;
            position: relative;
            overflow: hidden;
        }

        .announcement-modal-close::before {
            content: '';
            position: absolute;
            top: 50%;
            left: 50%;
            width: 0;
            height: 0;
            background: var(--accent-primary);
            border-radius: 50%;
            transform: translate(-50%, -50%);
            transition: all 0.3s ease;
            pointer-events: none;
            opacity: 0.1;
        }

        .announcement-modal-close:active::before {
            width: 80px;
            height: 80px;
        }

        .announcement-modal-close:hover {
            color: var(--accent-primary);
            background: var(--bg-secondary);
        }

        .announcement-modal-body {
            color: var(--text-primary);
            line-height: 1.6;
            font-size: 14px;
            border-left: 4px solid var(--accent-primary);
            padding-left: 20px;
            background: var(--bg-secondary);
            border-radius: 10px;
            padding: 20px;
        }

        .announcement-modal-body strong {
            color: var(--accent-primary);
            font-weight: 700;
        }

        @media (max-width: 768px) {
            .game-container {
                padding: 15px;
            }

            .control-bar {
                padding: 10px 20px;
                flex-direction: column;
                gap: 15px;
            }

