            });

            closeAnnouncementBtn.addEventListener('click', function() {
                announcementModal.classList.remove('show');
            });

            announcementModal.addEventListener('click', function(e) {
                if (e.target === announcementModal) {
                    announcementModal.classList.remove('show');
                }
            });

            document.addEventListener('keydown', function(e) {
                if (e.key === 'Escape' && announcementModal.classList.contains('show')) {
                    announcementModal.classList.remove('show');
                }
            });
        })();

        function setTheme(themeName) {
            document.documentElement.setAttribute('data-theme', themeName);
            localStorage.setItem('theme', themeName);

            document.querySelectorAll('.theme-btn').forEach(btn => {
                btn.classList.remove('active');
            });
            const activeBtn = document.querySelector(`.theme-btn[data-theme="${themeName}"]`);
            if (activeBtn) {
                activeBtn.classList.add('active');
            }
        }

        const savedTheme = localStorage.getItem('theme') || 'dark';
        setTheme(savedTheme);

        const triggerQuickReply = (text) => {
            if (!text || ['…', '...'].includes(text.trim()) || text.trim().length === 0) return;
            if (typeof triggerSlash === 'function') {
                triggerSlash(`/send ${text}|/trigger`);
            } else {
                console.log('SillyTavern environment not detected. Would send:', text);
            }
        };

        const smoothScrollToElement = (element) => {
            if (element) {
                element.scrollIntoView({
                    behavior: 'smooth',
                    block: 'start'
                });
            }
        };

        const storyPanel = document.getElementById('storyPanel');
        const locationPanel = document.getElementById('locationPanel');
        const locationContent = document.getElementById('locationContent');
        const toggleLocationBtn = document.getElementById('toggleLocationBtn');
        const showLocationsBtn = document.getElementById('showLocationsBtn');
        const toOptionsBtn = document.getElementById('toOptionsBtn');

        let isLocationView = false;

        const showLocationView = () => {
            isLocationView = true;
            locationContent.classList.add('active');
            locationPanel.style.display = 'block';
            storyPanel.style.display = 'none';
            toggleLocationBtn.textContent = '📖 Cố sự';

            setTimeout(() => {
                smoothScrollToElement(locationPanel);
            }, 100);
        };

        const showStoryView = () => {
            isLocationView = false;
            locationContent.classList.remove('active');
            locationPanel.style.display = 'none';
            storyPanel.style.display = 'block';
            toggleLocationBtn.textContent = '🗺️ Địa điểm';

            setTimeout(() => {
                smoothScrollToElement(storyPanel);
            }, 100);
        };

        toggleLocationBtn.addEventListener('click', () => {
            if (isLocationView) {
                showStoryView();
            } else {
                showLocationView();
            }
        });

        showLocationsBtn.addEventListener('click', showLocationView);

        toOptionsBtn.addEventListener('click', () => {
            if (isLocationView) {
                showStoryView();
            }
            setTimeout(() => {
                smoothScrollToElement(document.getElementById('optionsSection'));
            }, 100);
        });

        document.querySelector('.options-grid').addEventListener('click', function(e) {
            const button = e.target.closest('.option-btn');
            if (button) {
                const optionText = button.textContent.trim();
                triggerQuickReply(optionText);
            }
        });

        document.querySelectorAll('.location-card').forEach(card => {
            card.addEventListener('click', function() {
                const locationName = this.getAttribute('data-location');
                triggerQuickReply(`前往${locationName}`);
            });
        });

        showStoryView();
    </script>
</body>
</html>
